import React, { useState } from "react";
import { createVehicle } from "../services/api";

export default function VehicleForm({ onCreated }) {
  const [licensePlate, setLicensePlate] = useState("");
  const [status, setStatus] = useState("active");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");
    try {
      await createVehicle({ license_plate: licensePlate, status });
      setLicensePlate("");
      setStatus("active");
      onCreated && onCreated(); // trigger table refresh
    } catch (err) {
      console.error(err);
      setError("Could not add vehicle");
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      {error && <div style={{ color: "red" }}>{error}</div>}
      <input
        className="g-input"
        placeholder="KA-01-AB-1234"
        value={licensePlate}
        onChange={(e) => setLicensePlate(e.target.value)}
        required
      />
      <select
        className="g-input"
        value={status}
        onChange={(e) => setStatus(e.target.value)}
      >
        <option value="active">active</option>
        <option value="idle">idle</option>
        <option value="maintenance">maintenance</option>
      </select>
      <button className="g-btn" type="submit" disabled={loading}>
        {loading ? "Adding…" : "Add"}
      </button>
    </form>
  );
}
